ValidationRule.errorConditionFormula:
AND(
    NOT(
        OR(
            AND(
                NOT(ISBLANK(TEXT( InquiryType6__c ))),
                NOT(ISBLANK( Date6__c )),
                LEN ( URL6__c ) > 0
            ),
            AND(
                ISBLANK(TEXT( InquiryType6__c )),
                ISBLANK( Date6__c ),
                LEN ( URL6__c ) = 0
            )
        )
    ),
    NOT(
        OR(
            $Profile.Name = 'システム管理者',
            $Profile.Name = 'データ移行管理者'
        )
    )
)
